mapper.select:
SELECT layout_id, layout_type, floor_area_sqm, robot_total FROM v_factories WHERE layout_id IN
#{layoutId}
ORDER BY layout_id ASC

SELECT ranked.layout_id, ranked.scenario_id, ranked.snapshot_time, ranked.avg_delay_minutes_next_30m, ranked.order_inflow_15m, ranked.robot_active, ranked.robot_idle, ranked.robot_charging, ranked.avg_idle_duration_min, ranked.congestion_score FROM ( SELECT ws.layout_id, ws.scenario_id, ws.snapshot_time, ws.avg_delay_minutes_next_30m, ws.order_inflow_15m, ws.robot_active, ws.robot_idle, ws.robot_charging, ws.avg_idle_duration_min, ws.congestion_score, ROW_NUMBER() OVER ( PARTITION BY ws.layout_id ORDER BY ws.snapshot_time DESC, ws.scenario_id IS NULL ASC, ws.scenario_id ASC ) AS rn FROM warehouse_snapshot ws
WHERE ws.layout_id IN
#{layoutId}
) ranked WHERE ranked.rn = 1 ORDER BY ranked.layout_id ASC
